section.programlisting:
#
# Basic Rust Module Configuration
#
# Minimal config demonstrating the compiled-in functions:
# rate limiting, routing cache, and HTTP query.
#
# Usage:
#   opensips -c -f modules/rust/examples/basic.cfg   (syntax check)
#   opensips -f modules/rust/examples/basic.cfg       (run)
#

####### Global Parameters #########

log_level=3
log_stderror=no
log_facility=LOG_LOCAL0

udp_workers=4
auto_aliases=no

socket=udp:0.0.0.0:5060

####### Modules Section ###########

mpath="/usr/local/lib64/opensips/modules/"

loadmodule "proto_udp.so"
loadmodule "signaling.so"
loadmodule "sl.so"
loadmodule "tm.so"
loadmodule "rust.so"

# Rate limiter: 50 requests per 10-second window per source IP per worker
modparam("rust", "max_rate", 50)
modparam("rust", "window_seconds", 10)

# Routing cache: entries expire after 300 seconds
modparam("rust", "cache_ttl", 300)

# HTTP connection pool: 2-second timeout, 4 idle connections per host
modparam("rust", "http_timeout", 2)
modparam("rust", "pool_size", 4)

####### Routing Logic ###########

route {
    # ---- Rate Limiting ----
    # Returns 1 if allowed, -1 if exceeded.
    # On -1, a 429 reply is sent automatically.
    if (!rust_check_rate()) {
        xlog("L_WARN", "Rate limit exceeded for $si\n");
        exit;
    }

    # ---- Routing Cache ----
    # On hit: sets $du and returns 1.
    # On miss: returns -1.
    if (rust_cache_lookup()) {
        xlog("L_DBG", "Cache hit: $rU -> $du\n");
        t_relay();
        exit;
    }

    # ---- HTTP Lookup ----
    # Query an external routing service.
    # On success: $var(http_status)=HTTP code, $var(http_result)=body
    # On failure: returns -1
    if (rust_http_query("http://routing.internal/lookup?user=$rU")) {
        if ($var(http_status) == 200) {
            $du = $var(http_result);
            rust_cache_store();
            t_relay();
            exit;
        }
        xlog("L_WARN", "Routing API returned $var(http_status)\n");
    }

    sl_send_reply(404, "Not Found");
}

#
# Async Rust Module Configuration
#
# Demonstrates non-blocking HTTP queries using OpenSIPS async() with
# rust_exec(). The SIP worker is released during the HTTP call and
# resumes processing when the response arrives.
#
# Requires:
#   - rust.so module deployed
#   - User script with async_http_query handler deployed
#   - HTTP service running at the target URL
#
# Usage:
#   opensips -c -f modules/rust/examples/async.cfg   (syntax check)
#   opensips -f modules/rust/examples/async.cfg       (run)
#

####### Global Parameters #########

log_level=3
log_stderror=no
log_facility=LOG_LOCAL0

udp_workers=4
auto_aliases=no

socket=udp:0.0.0.0:5060

####### Modules Section ###########

mpath="/usr/local/lib64/opensips/modules/"

loadmodule "proto_udp.so"
loadmodule "signaling.so"
loadmodule "sl.so"
loadmodule "tm.so"
loadmodule "sipmsgops.so"
loadmodule "rust.so"

modparam("rust", "max_rate", 100)
modparam("rust", "window_seconds", 60)
modparam("rust", "http_timeout", 2)
modparam("rust", "pool_size", 4)

# User script with async_http_query handler
modparam("rust", "script_name",
    "/usr/local/lib64/opensips/scripts/libmy_opensips_handler.so")

####### Routing Logic ###########

route {
    if (!rust_check_rate()) {
        exit;
    }

    # ---- Async HTTP Query ----
    # Non-blocking: the worker is released during the HTTP call.
    # When the response arrives, route[http_done] executes.
    #
    # If the handler has no async variant (no async_http_query symbol),
    # the sync handler runs and route[http_done] executes immediately.
    async(rust_exec("http_query", "http://api.internal:8080/route/$rU"), http_done);
}

# Resume route — runs when the async HTTP response arrives.
# Available PVs set by the handler:
#   $var(http_status)  — HTTP status code (integer)
#   $var(http_body)    — response body (string, max 3800 bytes)
#   $var(http_json)    — full response as JSON object
#   $var(http_error)   — error message (empty on success)
#   $var(http_time_ms) — elapsed time in milliseconds
#   $avp(http_hdr)     — response headers (stacked AVP, one per header)
route[http_done] {
    if ($var(http_status) == 0) {
        xlog("L_ERR", "Async HTTP failed: $var(http_error)\n");
        sl_send_reply(503, "Service Unavailable");
        exit;
    }

    xlog("L_INFO", "HTTP $var(http_status) in $var(http_time_ms)ms\n");

    # Access the JSON response object
    if ($var(http_json)) {
        xlog("L_DBG", "Response JSON: $var(http_json)\n");
    }

    # Iterate response headers via stacked AVPs
    # Each $avp(http_hdr) contains one "Name: Value" header line.
    # Assign NULL to pop from the stack.
    while ($avp(http_hdr)) {
        xlog("L_DBG", "  Header: $avp(http_hdr)\n");
        $avp(http_hdr) = NULL;
    }

    # Route based on HTTP status
    if ($var(http_status) == 200) {
        # Use response body as destination
        $du = $var(http_body);
        t_relay();
        exit;
    }

    if ($var(http_status) == 404) {
        sl_send_reply(404, "Not Found");
        exit;
    }

    sl_send_reply(500, "Routing Error");
}

# ---- Sync Fallback Example ----
# When no URL is provided, the handler completes synchronously.
# The resume route still runs (async_status=ASYNC_SYNC), but
# $var(http_status) is 0 and $var(http_error) explains why.
route[async_no_url] {
    async(rust_exec("http_query"), http_done_noop);
}

route[http_done_noop] {
    # $var(http_status) == 0, $var(http_error) == "no URL: ..."
    xlog("L_DBG", "No-URL async completed: $var(http_error)\n");
    sl_send_reply(200, "OK");
}

#
# Rust Module Scripting Configuration
#
# Demonstrates rust_exec() with user-supplied handler scripts.
# Exercises both sync handlers and async handlers in a single config.
#
# Requires:
#   - rust.so module deployed
#   - User script .so deployed (libmy_opensips_handler.so)
#
# Usage:
#   opensips -c -f modules/rust/examples/scripting.cfg   (syntax check)
#   opensips -f modules/rust/examples/scripting.cfg       (run)
#

####### Global Parameters #########

log_level=3
log_stderror=no
log_facility=LOG_LOCAL0

udp_workers=4
auto_aliases=no

socket=udp:0.0.0.0:5060

####### Modules Section ###########

mpath="/usr/local/lib64/opensips/modules/"

loadmodule "proto_udp.so"
loadmodule "signaling.so"
loadmodule "sl.so"
loadmodule "tm.so"
loadmodule "sipmsgops.so"
loadmodule "textops.so"
loadmodule "rust.so"

# Module parameters
modparam("rust", "max_rate", 100)
modparam("rust", "window_seconds", 60)
modparam("rust", "cache_ttl", 300)
modparam("rust", "http_timeout", 2)
modparam("rust", "pool_size", 4)

# User script
modparam("rust", "script_name",
    "/usr/local/lib64/opensips/scripts/libmy_opensips_handler.so")

####### Routing Logic ###########

route {
    # ---- Rate Limiting (compiled-in) ----
    if (!rust_check_rate()) {
        exit;
    }

    # ---- Sync Script Handlers ----
    # These run in the current worker, blocking until complete.

    # Log request metadata (Call-ID, From, To, all headers)
    rust_exec("request_logger");

    # Set routing flags based on SIP method
    rust_exec("set_routing_flags");

    # Add custom header (requires textops.so)
    rust_exec("append_custom_header", "production");

    # ---- Variable Exchange: Config <-> Rust ----
    # Set $var(input), call Rust, read $var(output)
    $var(input) = "uppercase:hello from opensips";
    rust_exec("variable_exchange");
    xlog("L_DBG", "Transform result: $var(output)\n");

    # ---- Per-Worker Counter ----
    rust_exec("call_counter", "requests");
    xlog("L_DBG", "Worker request count: $var(count)\n");

    # ---- Cross-Worker Atomic Counter (compiled-in) ----
    rust_counter_inc();
    xlog("L_DBG", "Global request count: $var(shared_count)\n");

    # ---- PV Manipulation ----
    $var(pv_input) = "test-value";
    rust_exec("pv_manipulation");

    # ---- AVP Operations (transaction-scoped) ----
    rust_exec("avp_operations");

    # ---- JSON Parsing ----
    $var(json_input) = "{\"method\":\"INVITE\",\"src_ip\":\"10.0.0.1\"}";
    rust_exec("json_parse");
    xlog("L_DBG", "Parsed method: $var(json_method)\n");

    # ---- Sync HTTP Query (blocks worker) ----
    # For non-blocking HTTP, use async() instead — see async.cfg
    rust_exec("http_query", "http://127.0.0.1:8080/health");
    xlog("L_DBG", "HTTP status: $var(http_status)\n");

    sl_send_reply(200, "OK");
}
